import{_ as i,o as l,c as t,a2 as e}from"./chunks/framework.LN3EJxkW.js";const c=JSON.parse('{"title":"Auto Complete 自动完成","description":"","frontmatter":{"title":"Auto Complete 自动完成","stage":"intermediate","direction":"interaction-design","tags":["interaction-pattern","input","autocomplete"]},"headers":[],"relativePath":"03-interaction-design/notes/interaction-patterns/input/autocomplete.md","filePath":"03-interaction-design/notes/interaction-patterns/input/autocomplete.md","lastUpdated":1784382331000}'),s={name:"03-interaction-design/notes/interaction-patterns/input/autocomplete.md"};function n(r,a,o,h,d,p){return l(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="auto-complete-自动完成" tabindex="-1">Auto Complete 自动完成 <a class="header-anchor" href="#auto-complete-自动完成" aria-label="Permalink to &quot;Auto Complete 自动完成&quot;">​</a></h1><p>Auto Complete 自动完成把搜索字符串、候选集合、活动候选和已选对象组合为一个输入流程。它适合候选可检索但无法一次展示的场景，不等同于浏览器自动填充或普通文本建议。</p><h2 id="能力边界与前置知识" tabindex="-1">能力边界与前置知识 <a class="header-anchor" href="#能力边界与前置知识" aria-label="Permalink to &quot;能力边界与前置知识&quot;">​</a></h2><p>Auto Complete 自动完成负责把用户输入转换为可校验、可提交、可恢复的数据。它不能替代服务端授权、业务校验、唯一约束、恶意内容处理或并发控制。</p><p>前置知识：</p><ul><li>能定义字段或文档的数据类型、必填、范围和业务不变量；</li><li>能区分原始输入、显示值、规范化值和稳定对象 ID；</li><li>了解表单标签、可访问名称、焦点顺序和状态消息；</li><li>能观察请求、响应、对象版本和权威写入结果。</li></ul><h2 id="组成部分" tabindex="-1">组成部分 <a class="header-anchor" href="#组成部分" aria-label="Permalink to &quot;组成部分&quot;">​</a></h2><ul><li>输入值：用户当前文本，可能尚未对应对象。</li><li>选择值：稳定对象 ID，与显示名称分开。</li><li>候选源：本地词表或远程查询，包含权限过滤。</li><li>弹出列表：加载、无结果、错误、活动项和选中项。</li><li>提交规则：允许自由文本、必须选择，或允许创建新对象。</li></ul><p>查询文本、候选 ID、显示标签和最终选择必须分别建模。列表更新时活动候选仍按 ID 追踪，不能靠数组下标；提交时也不能把用户尚未确认的查询字符串当成已选对象。</p><h2 id="输入数据生命周期" tabindex="-1">输入数据生命周期 <a class="header-anchor" href="#输入数据生命周期" aria-label="Permalink to &quot;输入数据生命周期&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R[&quot;原始输入&quot;] --&gt; C[&quot;客户端可快速检查&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; N[&quot;规范化或对象选择&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    N --&gt; D[&quot;本地草稿&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; S[&quot;服务端授权与业务校验&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; W[&quot;受控写入&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    W --&gt; E[&quot;结果、版本与审计&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; F[&quot;字段、全局、冲突或临时错误&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; D</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h3 id="原始输入" tabindex="-1">原始输入 <a class="header-anchor" href="#原始输入" aria-label="Permalink to &quot;原始输入&quot;">​</a></h3><p>输入框保存用户正在组合的查询文本，并区分 <code>composition</code>、已提交查询和已确认选择。搜索层可以生成规范化查询副本，但不能把改写结果反写输入框导致光标跳动。</p><h3 id="规范化值" tabindex="-1">规范化值 <a class="header-anchor" href="#规范化值" aria-label="Permalink to &quot;规范化值&quot;">​</a></h3><p>候选的显示标签用于阅读，稳定 ID 才是选择值；同名对象通过类型、路径或辅助信息区分。大小写折叠、拼音或别名扩展只影响检索，不改变用户最终选择的对象身份。</p><h3 id="草稿" tabindex="-1">草稿 <a class="header-anchor" href="#草稿" aria-label="Permalink to &quot;草稿&quot;">​</a></h3><p>草稿分别记录查询文本和已选 ID。恢复时重新读取所选对象的当前标签与权限；若对象已删除或不可见，显示失效引用并要求重新选择，不能用缓存标签继续提交。</p><h3 id="权威结果" tabindex="-1">权威结果 <a class="header-anchor" href="#权威结果" aria-label="Permalink to &quot;权威结果&quot;">​</a></h3><p>远程搜索响应带查询序号或取消信号，只有最新查询可更新列表；选中后服务端仍要验证对象存在、可见且适用于当前字段。验证失败时保留查询并重新打开候选列表。</p><h2 id="专属行为" tabindex="-1">专属行为 <a class="header-anchor" href="#专属行为" aria-label="Permalink to &quot;专属行为&quot;">​</a></h2><ul><li>combobox 保持 DOM 焦点，aria-activedescendant 指向活动选项。</li><li>aria-expanded、aria-controls 和 aria-autocomplete 与真实行为一致。</li><li>输入变更后清除不再匹配的旧选择 ID。</li><li>中文等输入法 compositionend 前不提交候选。</li><li>远程查询设置最小输入、去抖、取消和乱序响应保护。</li></ul><h2 id="设计决策" tabindex="-1">设计决策 <a class="header-anchor" href="#设计决策" aria-label="Permalink to &quot;设计决策&quot;">​</a></h2><ol><li>自由文本与受控对象的业务差异。</li><li>同名候选需要哪些二级信息才能区分。</li><li>查询延迟和结果规模是否需要分页或分组。</li><li>无结果时允许创建、换词还是联系管理员。</li><li>缓存是否包含角色、租户、语言和数据版本。</li></ol><p>验收需要明确自由文本是否允许、何时发起查询、空结果怎样返回、活动候选怎样随键盘移动，以及乱序响应和对象失效时怎样恢复。</p><h2 id="状态模型" tabindex="-1">状态模型 <a class="header-anchor" href="#状态模型" aria-label="Permalink to &quot;状态模型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>状态</th><th>进入条件</th><th>界面责任</th><th>退出条件</th></tr></thead><tbody><tr><td>Auto Complete 自动完成未触碰</td><td>还没有本次交互</td><td>显示标签、规则和合理默认值</td><td>用户输入或选择</td></tr><tr><td>编辑中</td><td>原始值正在变化</td><td>保持焦点和输入法行为</td><td>完成输入、取消或提交</td></tr><tr><td>本地无效</td><td>可确定格式或范围错误</td><td>就近说明修正方式</td><td>输入变为有效</td></tr><tr><td>可提交</td><td>本地条件满足</td><td>主操作可用，不承诺业务成功</td><td>提交、继续编辑</td></tr><tr><td>提交中</td><td>请求或上传进行</td><td>防重复意图，保留输入</td><td>成功、失败、超时、取消</td></tr><tr><td>选择被拒绝</td><td>所选对象已删除、无权限或不再适用</td><td>保留查询文字，清除无效 ID 并解释原因</td><td>重新搜索或取消</td></tr><tr><td>冲突</td><td>基础对象版本变化</td><td>比较、刷新或合并</td><td>新版本确认</td></tr><tr><td>搜索状态未知</td><td>最新查询超时或连接中断</td><td>保留旧列表但标记已过期，不允许误认为完整结果</td><td>重试当前查询或输入新词</td></tr><tr><td>成功</td><td>权威结果完成</td><td>显示结果和下一步</td><td>后续操作</td></tr></tbody></table><p>状态不能只存在于颜色。错误、等待、选中、进度和保存结果应有程序化表达。</p><h2 id="工程状态示例" tabindex="-1">工程状态示例 <a class="header-anchor" href="#工程状态示例" aria-label="Permalink to &quot;工程状态示例&quot;">​</a></h2><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;query&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;shang&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;displayValue&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;上海市&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;selectedId&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;region-310000&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;activeOptionId&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;region-310000&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>示例字段不是通用接口标准。项目应按Auto Complete 自动完成的真实值类型定义 schema，并明确缺失值、无效值、服务端错误、版本和恢复语义。</p><h2 id="校验顺序" tabindex="-1">校验顺序 <a class="header-anchor" href="#校验顺序" aria-label="Permalink to &quot;校验顺序&quot;">​</a></h2><ol><li>Auto Complete 自动完成输入前说明格式、单位、范围和不可接受内容。</li><li>输入期间只做不会打断输入法的安全检查。</li><li>完成输入或离开字段后给出可修正反馈。</li><li>提交时客户端汇总当前已知错误。</li><li>服务端重新执行格式、授权、业务和并发校验。</li><li>返回字段错误与全局错误的稳定代码和安全文案。</li><li>界面保留合法输入，把焦点移到合理错误入口。</li><li>修正后只清除已经解决的错误。</li><li>成功后从权威响应更新对象和版本。</li></ol><p>客户端限制可以减少错误，不能防止直接请求、旧客户端或恶意输入。</p><h2 id="案例一-地址输入关联标准行政区-id" tabindex="-1">案例一：地址输入关联标准行政区 ID <a class="header-anchor" href="#案例一-地址输入关联标准行政区-id" aria-label="Permalink to &quot;案例一：地址输入关联标准行政区 ID&quot;">​</a></h2><h3 id="固定输入" tabindex="-1">固定输入 <a class="header-anchor" href="#固定输入" aria-label="Permalink to &quot;固定输入&quot;">​</a></h3><ul><li>使用合成账户与合成业务数据；</li><li>正常网络 80 ms，另注入 2 秒延迟和一次 503；</li><li>打开时对象版本为 17，提交前另一个会话更新为 18；</li><li>覆盖空值、无效值、长值、重复值和权限撤销；</li><li>记录可见结果、焦点、请求、响应和权威对象。</li></ul><h3 id="设计与实现" tabindex="-1">设计与实现 <a class="header-anchor" href="#设计与实现" aria-label="Permalink to &quot;设计与实现&quot;">​</a></h3><ol><li>combobox 保持 DOM 焦点，aria-activedescendant 指向活动选项。</li><li>aria-expanded、aria-controls 和 aria-autocomplete 与真实行为一致。</li><li>输入变更后清除不再匹配的旧选择 ID。</li><li>中文等输入法 compositionend 前不提交候选。</li><li>远程查询设置最小输入、去抖、取消和乱序响应保护。</li></ol><p>负责人选择成功后保存成员 ID，并用服务端返回的当前显示名和头像刷新输入；查询字符串不进入业务对象，旧缓存中的同名成员也不会替代已确认 ID。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>鼠标、键盘、触屏和屏幕阅读器都能完成；</li><li>输入法组合期间不误提交；</li><li>本地错误与服务端错误均能修正；</li><li>请求失败和冲突不清空合法工作；</li><li>重复触发只产生一个逻辑副作用；</li><li>最终显示与权威数据对账一致。</li></ul><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>乱序响应覆盖新查询并提交过期 ID</p><p>修复后重复相同输入和时序，确认界面状态、服务端副作用和审计记录同时正确。</p><h2 id="案例二-工单选择数万名成员中的处理人" tabindex="-1">案例二：工单选择数万名成员中的处理人 <a class="header-anchor" href="#案例二-工单选择数万名成员中的处理人" aria-label="Permalink to &quot;案例二：工单选择数万名成员中的处理人&quot;">​</a></h2><h3 id="固定输入-1" tabindex="-1">固定输入 <a class="header-anchor" href="#固定输入-1" aria-label="Permalink to &quot;固定输入&quot;">​</a></h3><ul><li>360 CSS px 视口与 200% 文本缩放；</li><li>系统大字体、中文输入法和仅键盘操作；</li><li>网络先离线，恢复后响应超时；</li><li>会话在未提交工作存在时到期；</li><li>数据包含同名对象、过期引用和被删除目标。</li></ul><h3 id="设计过程" tabindex="-1">设计过程 <a class="header-anchor" href="#设计过程" aria-label="Permalink to &quot;设计过程&quot;">​</a></h3><ol><li>查询框允许自由输入，但提交必须选择成员稳定 ID。</li><li>同名候选显示团队和邮箱域名等允许公开的区分信息。</li><li>输入法组合结束后去抖查询，取消旧请求并丢弃乱序响应。</li><li>输入文字变化后清除不再匹配的旧 selectedId。</li><li>方向键移动活动候选，Enter 选择，Escape 关闭。</li><li>提交前服务端重新检查成员仍可分配且当前用户有权限。</li></ol><p>窄屏候选列表与输入框保持视觉相邻，候选主标签、辅助身份和选中状态逐项排列；网络断开后关闭远程建议并保留查询，不把缓存候选标成当前完整结果。</p><h3 id="验证-1" tabindex="-1">验证 <a class="header-anchor" href="#验证-1" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>关闭和恢复网络后不重复写入；</li><li>刷新后按声明的草稿策略恢复；</li><li>会话到期不把敏感值写入不安全存储；</li><li>失效引用有替换、清除或返回路径；</li><li>读屏能获知结果而无需焦点被强制移动；</li><li>长文本不会遮挡唯一保存或取消动作。</li></ul><h3 id="失败分支-1" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支-1" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>会话在Auto Complete 自动完成进行中到期。界面必须暂停后续写入，保留允许保留的非敏感工作，重新认证后再次校验权限与版本；不能直接重放旧请求。</p><p>会话恢复时重新验证已选成员 ID：可见对象刷新标签，不可见对象显示“选择已失效”；未确认查询只作为本地文本恢复，不自动选择最接近的候选。</p><h2 id="无障碍实现" tabindex="-1">无障碍实现 <a class="header-anchor" href="#无障碍实现" aria-label="Permalink to &quot;无障碍实现&quot;">​</a></h2><h3 id="名称与说明" tabindex="-1">名称与说明 <a class="header-anchor" href="#名称与说明" aria-label="Permalink to &quot;名称与说明&quot;">​</a></h3><ul><li>Auto Complete 自动完成的可见标签进入可访问名称。</li><li>帮助文本与错误通过程序化关系关联。</li><li>placeholder 不替代持久可见标签。</li><li>必填、单位、格式和限制不只靠颜色或图标。</li><li>复合输入使用与真实行为匹配的 APG 模式。</li></ul><h3 id="键盘与输入法" tabindex="-1">键盘与输入法 <a class="header-anchor" href="#键盘与输入法" aria-label="Permalink to &quot;键盘与输入法&quot;">​</a></h3><ul><li>Auto Complete 自动完成的 Tab 顺序跟随 DOM 与视觉阅读顺序。</li><li>Enter、Space、方向键和 Escape 只按控件语义接管。</li><li>输入法 composition 期间不把中间文本当成完成值。</li><li>粘贴、语音输入和浏览器自动填充不被无理由阻止。</li><li>临时弹层关闭后焦点回到触发点或下一逻辑位置。</li><li>错误修正后焦点不被异步结果抢走。</li></ul><h3 id="重排" tabindex="-1">重排 <a class="header-anchor" href="#重排" aria-label="Permalink to &quot;重排&quot;">​</a></h3><p>在 320 CSS px 等效宽度和 200% 缩放下，弹出列表宽度不小于输入框，候选辅助文本可换行；活动候选始终滚入列表视口，但页面焦点仍留在 combobox 输入框。</p><h2 id="安全、性能与一致性" tabindex="-1">安全、性能与一致性 <a class="header-anchor" href="#安全、性能与一致性" aria-label="Permalink to &quot;安全、性能与一致性&quot;">​</a></h2><h3 id="安全" tabindex="-1">安全 <a class="header-anchor" href="#安全" aria-label="Permalink to &quot;安全&quot;">​</a></h3><ul><li>所有输入均视为不可信；</li><li>服务端重新授权和校验；</li><li>富文本与文件按输出上下文净化或隔离；</li><li>错误不泄露内部异常、受限对象或敏感路径；</li><li>日志不默认记录正文、文件内容、密码或令牌。</li></ul><h3 id="性能" tabindex="-1">性能 <a class="header-anchor" href="#性能" aria-label="Permalink to &quot;性能&quot;">​</a></h3><ul><li>取消失效查询并丢弃乱序响应；</li><li>长列表、长文档和大文件使用适合的分页、分片或后台任务；</li><li>加载优化不改变可访问树的完整语义；</li><li>缓存键包含租户、角色、语言和会改变结果的筛选条件；</li><li>性能预算覆盖输入响应、候选出现、提交和恢复。</li></ul><h3 id="一致性" tabindex="-1">一致性 <a class="header-anchor" href="#一致性" aria-label="Permalink to &quot;一致性&quot;">​</a></h3><ul><li>写请求带幂等或逻辑意图标识；</li><li>对现有对象修改带期望版本；</li><li>超时先查询结果而不是盲目重试；</li><li>部分成功返回逐项稳定 ID 与结果；</li><li>草稿与正式提交使用不同状态和权限；</li><li>客户端缓存不能静默覆盖服务端新版本。</li></ul><h2 id="调试与观测" tabindex="-1">调试与观测 <a class="header-anchor" href="#调试与观测" aria-label="Permalink to &quot;调试与观测&quot;">​</a></h2><ol><li>固定Auto Complete 自动完成的输入、角色、对象版本、网络、语言和视口。</li><li>检查原始值、显示值、选择 ID、错误和焦点。</li><li>检查请求参数、取消、响应顺序和业务错误码。</li><li>检查服务端授权、规范化、版本和权威写入。</li><li>注入超时、权限撤销、并发和页面刷新。</li><li>用键盘、读屏、输入法和窄屏重复。</li></ol><p>观测指标：</p><ul><li>有效开始、提交、成功、失败、取消和恢复；</li><li>首次错误类型与最终修正率；</li><li>输入丢失和重复副作用；</li><li>候选或校验响应延迟；</li><li>键盘阻断、焦点丢失和错误未关联；</li><li>按平台、语言、角色和数据量分群的完成时间。</li></ul><h2 id="综合练习" tabindex="-1">综合练习 <a class="header-anchor" href="#综合练习" aria-label="Permalink to &quot;综合练习&quot;">​</a></h2><p>为Auto Complete 自动完成完成可运行原型和服务端模拟。覆盖正常、无效、等待、失败、权限、过期、冲突、取消和未知结果。</p><p>验收：</p><ul><li>Auto Complete 自动完成的数据类型、显示值、提交值和稳定 ID 边界明确；</li><li>两个案例有固定输入、处理、结果、验证和失败；</li><li>客户端与服务端校验责任分开；</li><li>失败后保留允许保留的工作；</li><li>键盘、屏幕阅读器和输入法完成任务；</li><li>弱网、窄屏和长文本不隐藏恢复；</li><li>日志与分析不收集不必要敏感内容；</li><li>权威数据与界面结果可以对账。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.w3.org/WAI/ARIA/apg/patterns/combobox/" target="_blank" rel="noreferrer">W3C WAI — Combobox Pattern</a>（访问日期：2026-07-18）</li><li><a href="https://html.spec.whatwg.org/multipage/forms.html" target="_blank" rel="noreferrer">WHATWG — Forms</a>（访问日期：2026-07-18）</li><li><a href="https://www.w3.org/TR/WCAG22/" target="_blank" rel="noreferrer">W3C — Web Content Accessibility Guidelines (WCAG) 2.2</a>（访问日期：2026-07-18）</li></ul>`,79)])])}const b=i(s,[["render",n]]);export{c as __pageData,b as default};
